{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial search, noise management, and cost minimization. I am breaking it into subproblems for geometric modeling, probabilistic query strategy, and cost-benefit optimization.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. Create a function that, given a set of candidate placements on a grid, calculates the intersection of these placements with potential probe locations to identify high-probability overlap zones."
    },
    {
      "label": "probabilistic_query_optimizer",
      "instructions": "Develop a mathematical model for the noisy aggregate queries. Given a probability distribution of noise, calculate the expected information gain (reduction in entropy) for a single query at a specific location versus the cost of a direct drilling probe. Provide a threshold formula for when to switch from aggregate queries to drilling."
    },
    {
      "label": "cost_minimization_strategist",
      "instructions": "Formulate an objective function that minimizes the total cost: Total Cost = (Number of Drills * Drill Cost) + (Number of Aggregate Queries * Query Cost) + (Penalty for incorrect final guesses). Use the outputs from the geometric and probabilistic helpers to suggest an optimal sequence of actions that minimizes this function."
    }
  ],
  "synthesis_brief": "Combine the geometric overlap data with the probabilistic information gain thresholds to create a decision tree. Use the cost-minimization objective function to select the specific sequence of probes and queries that yields the lowest expected cost for the given polyomino shapes."
}

